import math

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, math.isqrt(n) + 1):
        if n % i == 0:
            return False
    return True

n = int(input())
print("Yes" if is_prime(n) else "No")

def average(nums):
    return sum(nums) / len(nums)

nums = list(map(float, input().split()))
print(round(average(nums), 2))
